// Helper function to normalize filename (remove extra spaces)
function normalizeFilename(filename) {
  return filename.replace(/\s+/g, ' ').trim();
}

// Get incoming data
const inputItems = $input.all();

// Get data from If8 (True Branch)
const if8Items = $('If8').all();

// Create map: normalized_filename -> attachment_id from If8
const attachmentMap = {};
for (const item of if8Items) {
  if (item.json.filename && item.json.attachment_id) {
    const normalizedFilename = normalizeFilename(item.json.filename);
    attachmentMap[normalizedFilename] = item.json.attachment_id;
  }
}

// Create map: original_filename -> file_type
const typeMap = {};
for (const item of inputItems) {
  if (item.json.output && item.json.output.file_type && item.json.output.original_filename) {
    typeMap[item.json.output.original_filename] = item.json.output.file_type;
  }
}

// Determine which types are already known
const knownTypes = Object.values(typeMap);
const hasDesign = knownTypes.includes('design');
const hasCreative = knownTypes.includes('creative');

// Determine missing type (if only one is known)
const missingType = hasDesign && !hasCreative ? 'creative' : !hasDesign && hasCreative ? 'design' : null;

// Update incoming data
const result = [];
for (const item of inputItems) {
  const fileName = item.json.output?.original_filename;
  const mimeType = item.json.output?.mimeType;

  // If file_type already exists, use it
  let fileType = item.json.output?.file_type;

  // If file_type is missing but there's a missing type, use it
  if (!fileType && missingType && fileName) {
    fileType = missingType;
  }

  // Search for attachment_id by normalized filename
  const normalizedFileName = normalizeFilename(fileName);
  let attachmentId = attachmentMap[normalizedFileName];

  // If not found by exact match, try partial match
  if (!attachmentId) {
    for (const [key, value] of Object.entries(attachmentMap)) {
      if (key.includes(normalizedFileName) || normalizedFileName.includes(key)) {
        attachmentId = value;
        break;
      }
    }
  }

  // Skip items without attachment_id or file_type
  if (!attachmentId || !fileType) {
    continue;
  }

  // Form result with needed structure
  result.push({
    attachment_id: attachmentId,
    filename: fileName,
    mimeType: mimeType,
    file_type: fileType
  });
}

return result;

