// Получаем название файла из узла "Get attachments1"
let theme = '';
try {
  const attachmentItem = $('Get attachments1').first();
  if (attachmentItem.json?.filename) {
    // Извлекаем название файла без расширения
    theme = attachmentItem.json.filename.replace(/\.[^/.]+$/, '');
  }
} catch (e) {
  console.log('Ошибка при получении темы из Get attachments1:', e.message);
}

// Получаем имена файлов из узла "Split Out1" (бинарные файлы дизайнов)
let binaryFileNames = [];
try {
  const splitOutItems = $('Split Out1').all();
  for (const item of splitOutItems) {
    if (item.binary) {
      // Получаем имя файла из бинарных данных
      const binaryKey = Object.keys(item.binary)[0];
      if (binaryKey && item.binary[binaryKey].fileName) {
        binaryFileNames.push(item.binary[binaryKey].fileName);
      }
    }
  }
} catch (e) {
  console.log('Ошибка при получении имён файлов из Split Out1:', e.message);
}

// Получаем items из узла "kieai - upload image" (design)
let designFiles = [];
try {
  const designItems = $('kieai - upload image').all();
  for (let i = 0; i < designItems.length; i++) {
    const item = designItems[i];
    if (item.json?.data) {
      designFiles.push({
        downloadUrl: item.json.data.downloadUrl,
        fileSize: item.json.data.fileSize,
        // Используем имя из бинарного файла, если оно есть, иначе из ссылки
        fileName: binaryFileNames[i] || item.json.data.fileName
      });
    }
  }
} catch (e) {
  console.log('Ошибка при получении дизайнов:', e.message);
}

// Сортируем дизайны по номеру в названии файла (mocap_1, mocap_2, mocap_3...)
designFiles.sort((a, b) => {
  const numA = parseInt(a.fileName.match(/\d+/) || 0);
  const numB = parseInt(b.fileName.match(/\d+/) || 0);
  return numA - numB;
});

// Получаем items из узла "kieai - upload image1" (creative)
let creativeFiles = [];
try {
  const creativeItems = $('kieai - upload image1').all();
  for (const item of creativeItems) {
    if (item.json?.data) {
      creativeFiles.push({
        downloadUrl: item.json.data.downloadUrl,
        fileSize: item.json.data.fileSize,
        fileName: item.json.data.fileName
      });
    }
  }
} catch (e) {
  console.log('Ошибка при получении креативов:', e.message);
}

// Собираем design_urls и design_names
const designUrls = designFiles.map(f => f.downloadUrl).join(', ');
const designNames = designFiles.map(f => f.fileName).join(', ');

// Собираем all_urls в правильном порядке (дизайны + креативы)
const allUrls = [
  ...designFiles.map(f => f.downloadUrl),
  ...creativeFiles.map(f => f.downloadUrl)
].join(', ');

const result = {
  json: {
    theme: theme,
    design: {
      uploaded_files: designFiles,
      binary_count: designFiles.length
    },
    creative: {
      uploaded_files: creativeFiles,
      binary_count: creativeFiles.length
    },
    design_urls: designUrls,
    design_names: designNames,
    all_urls: allUrls
  }
};

return [result];

// Получаем количество экранов из creative_task
let totalScreens = 0;
try {
  const creativeTaskRaw = $input.first().json.creative_task;
  const creativeTask = JSON.parse(creativeTaskRaw);
  totalScreens = parseInt(creativeTask.total_screens) || 0;
} catch (e) {
  console.log('Ошибка при парсинге creative_task:', e.message);
}

// Получаем дизайны и креативы из Code - Counter
let designFiles = [];
let creativeFiles = [];
let mocapMap = {}; // { mocapNumber: downloadUrl }

try {
  const counterData = $('Code - Counter').first().json;

  // Получаем дизайны
  if (counterData.design && counterData.design.uploaded_files) {
    designFiles = counterData.design.uploaded_files;

    // Создаём map: mocapNumber -> downloadUrl
    // Пытаемся найти номер в разных форматах
    for (const file of designFiles) {
      let mocapNumber = null;

      // Попытка 1: Ищем mocap_(\d+)
      let match = file.fileName.match(/mocap_(\d+)/);
      if (match) {
        mocapNumber = parseInt(match[1]);
      }

      // Попытка 2: Ищем число в скобках (\d+)
      if (!mocapNumber) {
        match = file.fileName.match(/\((\d+)\)/);
        if (match) {
          mocapNumber = parseInt(match[1]);
        }
      }

      // Попытка 3: Ищем просто число в начале или конце
      if (!mocapNumber) {
        match = file.fileName.match(/^(\d+)|(\d+)(?=\.\w+$)/);
        if (match) {
          mocapNumber = parseInt(match[1] || match[2]);
        }
      }

      // Если нашли номер, добавляем в map
      if (mocapNumber) {
        mocapMap[mocapNumber] = file.downloadUrl;
      }
    }
  }

  // Получаем креативы
  if (counterData.creative && counterData.creative.uploaded_files) {
    creativeFiles = counterData.creative.uploaded_files;
  }
} catch (e) {
  console.log('Ошибка при получении данных из Code - Counter:', e.message);
}

// Собираем all_urls (креативы + дизайны)
const allUrls = [
  ...creativeFiles.map(f => f.downloadUrl),
  ...designFiles.map(f => f.downloadUrl)
].join(', ');

// Создаём screen_mocaps объект
const screenMocaps = {};
for (let i = 1; i <= totalScreens; i++) {
  const screenKey = `screen_${i}`;
  const mocapUrl = mocapMap[i] || null;
  screenMocaps[screenKey] = {
    downloadUrl: mocapUrl
  };
}

// Создаём mocap_analyze объект
const mocapAnalyzeScreens = {};
for (let i = 1; i <= totalScreens; i++) {
  const screenKey = `screen_${i}`;
  const mocapNumber = mocapMap[i] ? i : null;
  mocapAnalyzeScreens[screenKey] = mocapNumber;
}

const mocapAnalyze = {
  screens: mocapAnalyzeScreens,
  comments: {}
};

// Создаём screens_string
const screenEntries = [];
for (let i = 1; i <= totalScreens; i++) {
  const mocapValue = mocapMap[i] ? i : 'null';
  screenEntries.push(`"screen_${i}": ${mocapValue}`);
}
const screensString = screenEntries.join(', ');

// Формируем результат
const result = {
  json: {
    screens_string: screensString,
    total_screens: totalScreens,
    design: {
      uploaded_files: designFiles,
      binary_count: designFiles.length
    },
    creative: {
      uploaded_files: creativeFiles,
      binary_count: creativeFiles.length
    },
    all_urls: allUrls,
    screen_mocaps: screenMocaps,
    mocap_analyze: mocapAnalyze
  }
};

return [result];

