const dataStr = $json.data;
const parsed = JSON.parse(dataStr);
const content = parsed.choices[0].message.content;

const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/);
const jsonStr = jsonMatch ? jsonMatch[1] : content;

const result = JSON.parse(jsonStr);
const jsonString = JSON.stringify(result);

return [
  {
    json: {
      content: {
        parts: [
          {
            text: jsonString
          }
        ]
      }
    }
  }
];

const input = $input.first().json.text;

let result = '';
if (typeof input === 'string') {
  result = input;
} else {
  return [{ json: { error: 'Invalid input type', received: input } }];
}

let cleanedText = result;

cleanedText = cleanedText.replace(/\\n/g, ' ');
cleanedText = cleanedText.replace(/\\r/g, ' ');
cleanedText = cleanedText.replace(/\\t/g, ' ');

cleanedText = cleanedText.replace(/[\r\n\t]+/g, ' ');

cleanedText = cleanedText.replace(/\\"/g, '');
cleanedText = cleanedText.replace(/\\/g, '');
cleanedText = cleanedText.replace(/\//g, ' ');

cleanedText = cleanedText.replace(/nn(?=[A-Z])/g, ' ');
cleanedText = cleanedText.replace(/([:;,.?!])n(?=[A-Z])/g, '$1 ');
cleanedText = cleanedText.replace(/([a-z])n([A-Z])/g, '$1 $2');
cleanedText = cleanedText.replace(/ nn /g, ' ');

cleanedText = cleanedText.replace(/[•●]/g, '-');

cleanedText = cleanedText.replace(/["'`«»]/g, '');

cleanedText = cleanedText.replace(/[{}[\]]/g, '');

cleanedText = cleanedText.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

cleanedText = cleanedText.replace(/[\x00-\x1F\x7F]/g, '');

cleanedText = cleanedText.replace(/\s+/g, ' ').trim();

return [
  {
    json: {
      ClearPromt: cleanedText,
    }
  }
];
